package subdomain

import (
	"context"
	"fmt"
	"strings"
	"sync"
	"testing"

	"github.com/yaklang/yaklang/common/log"
)

// fakeQuerier is a deterministic, in-process aRecordQuerier used to exercise
// the wildcard detection algorithm without real DNS. It distinguishes wildcard
// *probes* (a 16-char random label generated by isWildCard) from *dictionary*
// brute entries by the length of the first label of the queried domain.
type fakeQuerier struct {
	mu sync.Mutex
	// probeIPs is the pool of IPs returned for wildcard probes (first label
	// length == 16). An empty pool means "all probes fail to resolve".
	probeIPs []string
	// probeIdx tracks round-robin position in probeIPs.
	probeIdx int
	// dictIP is the IP returned for dictionary brute entries (first label
	// length != 16). Empty means "fail to resolve".
	dictIP string
	// queries records every domain queried, for assertions.
	queries []string
}

func (f *fakeQuerier) QueryA(_ context.Context, domain string) (ip string, server string, _ error) {
	f.mu.Lock()
	defer f.mu.Unlock()

	f.queries = append(f.queries, domain)

	// strip trailing dot
	d := strings.TrimSuffix(domain, ".")
	first := d
	if idx := strings.Index(d, "."); idx > 0 {
		first = d[:idx]
	}

	// isWildCard generates 16-char random labels; dictionary entries are short.
	if len(first) == 16 {
		if len(f.probeIPs) == 0 {
			return "", "", fmt.Errorf("nxdomain: %s", domain)
		}
		ip := f.probeIPs[f.probeIdx%len(f.probeIPs)]
		f.probeIdx++
		return ip, "fake", nil
	}

	if f.dictIP == "" {
		return "", "", fmt.Errorf("nxdomain: %s", domain)
	}
	return f.dictIP, "fake", nil
}

func newTestScanner(t *testing.T, q aRecordQuerier) *SubdomainScanner {
	t.Helper()
	cfg := NewSubdomainScannerConfig()
	cfg.WildCardProbeCount = 10
	cfg.WildCardToStop = false
	cfg.WorkerCount = 50
	cfg.MainDictionary = []byte("www\nmail\nftp\n")
	cfg.SubDictionary = []byte("sub\n")
	cfg.MaxDepth = 1
	cfg.AllowToRecursive = false
	cfg.TimeoutForEachQuery = 0

	s, err := NewSubdomainScannerWithLogger(cfg, log.GetLogger("subdomain-test"), "example.com")
	if err != nil {
		t.Fatalf("build scanner: %v", err)
	}
	if q != nil {
		s.UseQuerier(q)
	}
	return s
}

// TestIsWildCard_None covers the case where every random probe fails to
// resolve (no wildcard at all).
func TestIsWildCard_None(t *testing.T) {
	q := &fakeQuerier{probeIPs: nil, dictIP: "1.2.3.4"}
	s := newTestScanner(t, q)

	mode, tested, blacklist := s.isWildCard(context.Background(), "example.com")
	if mode != WildcardNone {
		t.Fatalf("expected WildcardNone, got %v (tested=%v blacklist=%v)", mode, tested, blacklist)
	}
	if len(tested) != 0 || len(blacklist) != 0 {
		t.Fatalf("expected empty tested/blacklist, got tested=%v blacklist=%v", tested, blacklist)
	}
}

// TestIsWildCard_PartialHit covers the case where only some probes resolve.
// This must NOT be classified as wildcard (avoid false positives).
func TestIsWildCard_PartialHit(t *testing.T) {
	// 5 probe IPs in the pool, but probe count is 10: probes 6..10 will
	// wrap around and re-resolve, so this would actually fully resolve.
	// To force a genuine partial hit, use a querier that fails after N hits.
	q := &partialFailQuerier{hitBeforeFail: 4, dictIP: "1.2.3.4"}
	s := newTestScanner(t, q)

	mode, tested, blacklist := s.isWildCard(context.Background(), "example.com")
	if mode != WildcardNone {
		t.Fatalf("expected WildcardNone for partial hit, got %v (tested=%v)", mode, tested)
	}
	if len(tested) == 0 {
		t.Fatalf("expected some probes resolved before failure")
	}
	if len(blacklist) != 0 {
		t.Fatalf("expected empty blacklist for WildcardNone, got %v", blacklist)
	}
}

// partialFailQuerier resolves the first hitBeforeFail probes then fails.
type partialFailQuerier struct {
	mu            sync.Mutex
	hits          int
	hitBeforeFail int
	dictIP        string
}

func (p *partialFailQuerier) QueryA(_ context.Context, domain string) (string, string, error) {
	p.mu.Lock()
	defer p.mu.Unlock()
	d := strings.TrimSuffix(domain, ".")
	first := d
	if idx := strings.Index(d, "."); idx > 0 {
		first = d[:idx]
	}
	if len(first) == 16 {
		if p.hits >= p.hitBeforeFail {
			return "", "", fmt.Errorf("nxdomain: %s", domain)
		}
		p.hits++
		return fmt.Sprintf("10.0.0.%d", p.hits), "fake", nil
	}
	if p.dictIP == "" {
		return "", "", fmt.Errorf("nxdomain: %s", domain)
	}
	return p.dictIP, "fake", nil
}

// TestIsWildCard_SingleIP covers the classic wildcard case: all probes
// resolve to the same IP.
func TestIsWildCard_SingleIP(t *testing.T) {
	q := &fakeQuerier{probeIPs: []string{"6.6.6.6"}, dictIP: "1.2.3.4"}
	s := newTestScanner(t, q)

	mode, tested, blacklist := s.isWildCard(context.Background(), "example.com")
	if mode != WildcardSingleIP {
		t.Fatalf("expected WildcardSingleIP, got %v (tested=%v blacklist=%v)", mode, tested, blacklist)
	}
	if len(tested) != 10 {
		t.Fatalf("expected 10 tested probes, got %d", len(tested))
	}
	if len(blacklist) != 1 || blacklist[0] != "6.6.6.6" {
		t.Fatalf("expected blacklist=[6.6.6.6], got %v", blacklist)
	}
}

// TestIsWildCard_Hijacked covers the DNS-hijack case: all probes resolve but
// return distinct IPs.
func TestIsWildCard_Hijacked(t *testing.T) {
	ips := []string{"203.0.113.1", "203.0.113.2", "203.0.113.3", "203.0.113.4", "203.0.113.5"}
	q := &fakeQuerier{probeIPs: ips, dictIP: "203.0.113.99"}
	s := newTestScanner(t, q)

	mode, tested, blacklist := s.isWildCard(context.Background(), "example.com")
	if mode != WildcardHijacked {
		t.Fatalf("expected WildcardHijacked, got %v (tested=%v blacklist=%v)", mode, tested, blacklist)
	}
	if len(tested) != 10 {
		t.Fatalf("expected 10 tested probes, got %d", len(tested))
	}
	if len(blacklist) < 2 {
		t.Fatalf("expected >=2 distinct IPs in blacklist for hijack, got %v", blacklist)
	}
}

// TestBrute_AbortsOnHijack verifies that BruteWithSubDictionarySelection
// stops immediately on hijack and fires the OnScanAborted callback, emitting
// no results.
func TestBrute_AbortsOnHijack(t *testing.T) {
	ips := []string{"203.0.113.1", "203.0.113.2", "203.0.113.3", "203.0.113.4", "203.0.113.5"}
	q := &fakeQuerier{probeIPs: ips, dictIP: "203.0.113.99"}
	s := newTestScanner(t, q)

	var (
		results []string
		aborted string
		abMu    sync.Mutex
	)
	s.OnResult(func(r *SubdomainResult) {
		results = append(results, r.Domain)
	})
	s.OnScanAborted(func(reason string) {
		abMu.Lock()
		defer abMu.Unlock()
		aborted = reason
	})

	s.Brute(context.Background(), "example.com")

	if len(results) != 0 {
		t.Fatalf("expected no brute results on hijack, got %v", results)
	}
	if aborted == "" {
		t.Fatalf("expected OnScanAborted to fire with a reason")
	}
	if !strings.Contains(aborted, "hijacked") && !strings.Contains(aborted, "hijack") {
		t.Fatalf("expected reason to mention hijack, got: %s", aborted)
	}
	if !strings.Contains(aborted, "example.com") {
		t.Fatalf("expected reason to mention target, got: %s", aborted)
	}
}

// TestBrute_SingleIPBlacklist verifies that under classic wildcard (single IP),
// brute force proceeds and dictionary entries resolving to the wildcard IP
// are filtered out, while entries resolving to a different IP are emitted.
func TestBrute_SingleIPBlacklist(t *testing.T) {
	// wildcard IP = 6.6.6.6; dictionary entries resolve to 7.7.7.7 (emitted).
	q := &fakeQuerier{probeIPs: []string{"6.6.6.6"}, dictIP: "7.7.7.7"}
	s := newTestScanner(t, q)

	var results []string
	s.OnResult(func(r *SubdomainResult) {
		results = append(results, r.Domain)
	})

	s.Brute(context.Background(), "example.com")

	if len(results) == 0 {
		t.Fatalf("expected dictionary entries to be emitted under single-IP wildcard, got none")
	}
	for _, d := range results {
		if !strings.HasSuffix(d, "example.com") {
			t.Fatalf("unexpected result domain: %s", d)
		}
	}
}

// TestBrute_NoWildcard verifies normal brute force with no wildcard emits
// dictionary results.
func TestBrute_NoWildcard(t *testing.T) {
	q := &fakeQuerier{probeIPs: nil, dictIP: "8.8.8.8"}
	s := newTestScanner(t, q)

	var results []string
	s.OnResult(func(r *SubdomainResult) {
		results = append(results, r.Domain)
	})

	s.Brute(context.Background(), "example.com")

	if len(results) == 0 {
		t.Fatalf("expected dictionary results with no wildcard, got none")
	}
}

// TestBrute_WildCardToStop verifies that under classic single-IP wildcard
// with WildCardToStop=true, brute force emits nothing and does not abort.
func TestBrute_WildCardToStop(t *testing.T) {
	q := &fakeQuerier{probeIPs: []string{"6.6.6.6"}, dictIP: "7.7.7.7"}
	s := newTestScanner(t, q)
	s.config.WildCardToStop = true

	var (
		results []string
		aborted string
		abMu    sync.Mutex
	)
	s.OnResult(func(r *SubdomainResult) {
		results = append(results, r.Domain)
	})
	s.OnScanAborted(func(reason string) {
		abMu.Lock()
		defer abMu.Unlock()
		aborted = reason
	})

	s.Brute(context.Background(), "example.com")

	if len(results) != 0 {
		t.Fatalf("expected no results when WildCardToStop=true, got %v", results)
	}
	if aborted != "" {
		t.Fatalf("expected no abort on classic wildcard stop, got: %s", aborted)
	}
}
